import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'
import * as BaseSwitch from '../../base-ui/switch'

// MODEL

export type SwitchChangeReason = BaseSwitch.SwitchChangeReason
export type SwitchCheckedChange = BaseSwitch.SwitchCheckedChange
export type SwitchCheckedState = BaseSwitch.SwitchCheckedState

export const SwitchSize = S.Union([S.Literal('sm'), S.Literal('default')])
export type SwitchSize = typeof SwitchSize.Type

export const SwitchStyleOptions = S.Struct({
  className: S.optional(S.String),
  thumbClassName: S.optional(S.String),
  size: S.optional(SwitchSize),
})
export type SwitchStyleOptions = typeof SwitchStyleOptions.Type

// UPDATE

export const { checkedChange, checkedState } = BaseSwitch

// VIEW

export type SwitchAttributes<Message> = BaseSwitch.SwitchAttributes<Message>

export type ViewConfig<Message> = Omit<
  BaseSwitch.ViewConfig<Message>,
  'toView'
> &
  SwitchStyleOptions &
  Readonly<{
    dir?: string
    toView?: (attributes: SwitchAttributes<Message>) => Html
  }>

export const switchBaseClassName =
  'peer group/switch relative inline-flex shrink-0 items-center rounded-full border border-transparent transition-all outline-none after:absolute after:-inset-x-3 after:-inset-y-2 focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 data-[size=default]:h-[18.4px] data-[size=default]:w-[32px] data-[size=sm]:h-[14px] data-[size=sm]:w-[24px] dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 data-checked:bg-primary data-unchecked:bg-input dark:data-unchecked:bg-input/80 data-disabled:cursor-not-allowed data-disabled:opacity-50'

export const switchThumbBaseClassName =
  'pointer-events-none block rounded-full bg-background ring-0 transition-transform group-data-[size=default]/switch:size-4 group-data-[size=sm]/switch:size-3 group-data-[size=default]/switch:data-checked:translate-x-[calc(100%-2px)] group-data-[size=sm]/switch:data-checked:translate-x-[calc(100%-2px)] dark:data-checked:bg-primary-foreground group-data-[size=default]/switch:data-unchecked:translate-x-0 group-data-[size=sm]/switch:data-unchecked:translate-x-0 dark:data-unchecked:bg-foreground'

export const switchRtlThumbBaseClassName =
  'pointer-events-none block rounded-full bg-background ring-0 transition-transform group-data-[size=default]/switch:size-4 group-data-[size=sm]/switch:size-3 group-data-[size=default]/switch:data-checked:translate-x-[calc(100%-2px)] group-data-[size=sm]/switch:data-checked:translate-x-[calc(100%-2px)] rtl:group-data-[size=default]/switch:data-checked:-translate-x-[calc(100%-2px)] rtl:group-data-[size=sm]/switch:data-checked:-translate-x-[calc(100%-2px)] dark:data-checked:bg-primary-foreground group-data-[size=default]/switch:data-unchecked:translate-x-0 group-data-[size=sm]/switch:data-unchecked:translate-x-0 rtl:group-data-[size=default]/switch:data-unchecked:-translate-x-0 rtl:group-data-[size=sm]/switch:data-unchecked:-translate-x-0 dark:data-unchecked:bg-foreground'

export const switchClassName = ({
  className,
}: Pick<SwitchStyleOptions, 'className'> = {}): string =>
  cn(switchBaseClassName, className)

export const switchThumbClassName = (
  options?: Readonly<{
    className?: string | undefined
    dir?: string | undefined
  }>,
): string =>
  cn(
    options?.dir === 'rtl'
      ? switchRtlThumbBaseClassName
      : switchThumbBaseClassName,
    options?.className,
  )

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'className' | 'dir' | 'size'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'switch'),
  h.DataAttribute('size', config.size ?? 'default'),
  h.Class(switchClassName({ className: config.className })),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
]

const thumbAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'dir' | 'thumbClassName'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'switch-thumb'),
  h.Class(
    switchThumbClassName({
      className: config.thumbClassName,
      dir: config.dir,
    }),
  ),
]

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: SwitchAttributes<Message>,
): SwitchAttributes<Message> => ({
  root: [...attributes.root, ...rootAttributes(h, config)],
  thumb: [...attributes.thumb, ...thumbAttributes(h, config)],
  input: attributes.input,
  uncheckedInput: attributes.uncheckedInput,
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, ...baseConfig } = config

  return BaseSwitch.view<Message>({
    ...baseConfig,
    toView: attributes => {
      const switchAttributes = shadcnAttributes(h, config, attributes)

      if (toView !== undefined) {
        return toView(switchAttributes)
      }

      return h.span(
        [...switchAttributes.root],
        [h.span([...switchAttributes.thumb], [])],
      )
    },
  })
}

import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'
import { view as Switch } from './index'
import type { SwitchSize } from './index'

const fieldBaseClassName =
  'group/field flex w-full gap-2 data-[invalid=true]:text-destructive'
const fieldHorizontalClassName =
  'flex-row items-center has-[>[data-slot=field-content]]:items-start *:data-[slot=field-label]:flex-auto has-[>[data-slot=field-content]]:[&>[role=checkbox],[role=radio]]:mt-px'
const fieldGroupClassName =
  'group/field-group @container/field-group flex w-full flex-col gap-5 data-[slot=checkbox-group]:gap-3 *:data-[slot=field-group]:gap-4'
const fieldContentClassName =
  'group/field-content flex flex-1 flex-col gap-0.5 leading-snug'
const labelClassName =
  'flex items-center gap-2 text-sm leading-none font-medium select-none group-data-[disabled=true]:pointer-events-none group-data-[disabled=true]:opacity-50 peer-disabled:cursor-not-allowed peer-disabled:opacity-50'
const fieldLabelClassName =
  'items-center text-sm font-medium select-none group-data-[disabled=true]:pointer-events-none group-data-[disabled=true]:opacity-50 peer-disabled:cursor-not-allowed peer-disabled:opacity-50 group/field-label peer/field-label flex w-fit gap-2 leading-snug group-data-[disabled=true]/field:opacity-50 has-data-checked:border-primary/30 has-data-checked:bg-primary/5 has-[>[data-slot=field]]:rounded-lg has-[>[data-slot=field]]:border *:data-[slot=field]:p-2.5 dark:has-data-checked:border-primary/20 dark:has-data-checked:bg-primary/10 has-[>[data-slot=field]]:w-full has-[>[data-slot=field]]:flex-col'
const fieldTitleClassName =
  'flex w-fit items-center gap-2 text-sm font-medium group-data-[disabled=true]/field:opacity-50'
const fieldDescriptionClassName =
  'text-left text-sm leading-normal font-normal text-muted-foreground group-has-data-horizontal/field:text-balance [[data-variant=legend]+&]:-mt-1.5 last:mt-0 nth-last-2:-mt-1 [&>a]:underline [&>a]:underline-offset-4 [&>a:hover]:text-primary'
const fieldDescriptionRtlClassName =
  'text-start text-sm leading-normal font-normal text-muted-foreground group-has-data-horizontal/field:text-balance [[data-variant=legend]+&]:-mt-1.5 last:mt-0 nth-last-2:-mt-1 [&>a]:underline [&>a]:underline-offset-4 [&>a:hover]:text-primary'

const fieldAttributes = (
  h: ReturnType<typeof html<never>>,
  config: Readonly<{
    className?: string
    isDisabled?: boolean
    isInvalid?: boolean
    dir?: string
  }> = {},
): ReadonlyArray<Attribute<never>> => [
  h.Role('group'),
  h.DataAttribute('slot', 'field'),
  h.DataAttribute('orientation', 'horizontal'),
  h.Class(cn(fieldBaseClassName, fieldHorizontalClassName, config.className)),
  ...(config.isDisabled === true ? [h.Attribute('data-disabled', 'true')] : []),
  ...(config.isInvalid === true ? [h.Attribute('data-invalid', 'true')] : []),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
]

const fieldGroupAttributes = (
  h: ReturnType<typeof html<never>>,
  className?: string,
): ReadonlyArray<Attribute<never>> => [
  h.DataAttribute('slot', 'field-group'),
  h.Class(cn(fieldGroupClassName, className)),
]

const fieldContentAttributes = (
  h: ReturnType<typeof html<never>>,
): ReadonlyArray<Attribute<never>> => [
  h.DataAttribute('slot', 'field-content'),
  h.Class(fieldContentClassName),
]

const labelAttributes = (
  h: ReturnType<typeof html<never>>,
  config: Readonly<{
    htmlFor?: string
    className?: string
    field?: boolean
    dir?: string
  }> = {},
): ReadonlyArray<Attribute<never>> => [
  h.DataAttribute('slot', config.field === true ? 'field-label' : 'label'),
  h.Class(
    cn(
      config.field === true ? fieldLabelClassName : labelClassName,
      config.className,
    ),
  ),
  ...(config.htmlFor === undefined ? [] : [h.Attribute('for', config.htmlFor)]),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
]

const fieldTitleAttributes = (
  h: ReturnType<typeof html<never>>,
): ReadonlyArray<Attribute<never>> => [
  h.DataAttribute('slot', 'field-label'),
  h.Class(fieldTitleClassName),
]

const fieldDescriptionAttributes = (
  h: ReturnType<typeof html<never>>,
  dir?: string,
): ReadonlyArray<Attribute<never>> => [
  h.DataAttribute('slot', 'field-description'),
  h.Class(
    dir === 'rtl' ? fieldDescriptionRtlClassName : fieldDescriptionClassName,
  ),
  ...(dir === undefined ? [] : [h.Dir(dir)]),
]

const switchControl = (
  h: ReturnType<typeof html<never>>,
  config: Readonly<{
    id: string
    isChecked?: boolean
    isDisabled?: boolean
    isInvalid?: boolean
    size?: SwitchSize
    dir?: string
  }>,
): ReadonlyArray<Html> => {
  const baseConfig = {
    id: config.id,
    isChecked: config.isChecked ?? false,
    ...(config.isDisabled === undefined
      ? {}
      : { isDisabled: config.isDisabled }),
    ...(config.isInvalid === undefined ? {} : { isInvalid: config.isInvalid }),
    ...(config.size === undefined ? {} : { size: config.size }),
    ...(config.dir === undefined ? {} : { dir: config.dir }),
  }
  const switchInput = Switch<never>({
    ...baseConfig,
    toView: attributes =>
      h.span([...attributes.root], [h.span([...attributes.thumb], [])]),
  })

  const input = Switch<never>({
    ...baseConfig,
    toView: attributes => h.input([...attributes.input]),
  })

  return [switchInput, input]
}

export const SwitchDemo = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex items-center space-x-2')],
    [
      ...switchControl(h, { id: 'airplane-mode' }),
      h.label(
        [...labelAttributes(h, { htmlFor: 'airplane-mode' })],
        ['Airplane Mode'],
      ),
    ],
  )
}

export const SwitchDescription = (): Html => {
  const h = html<never>()

  return h.div(
    [...fieldAttributes(h, { className: 'max-w-sm' })],
    [
      h.div(
        [...fieldContentAttributes(h)],
        [
          h.label(
            [
              ...labelAttributes(h, {
                htmlFor: 'switch-focus-mode',
                field: true,
              }),
            ],
            ['Share across devices'],
          ),
          h.p(
            [...fieldDescriptionAttributes(h)],
            [
              'Focus is shared across devices, and turns off when you leave the app.',
            ],
          ),
        ],
      ),
      ...switchControl(h, { id: 'switch-focus-mode' }),
    ],
  )
}

export const SwitchChoiceCard = (): Html => {
  const h = html<never>()

  return h.div(
    [...fieldGroupAttributes(h, 'w-full max-w-sm')],
    [
      h.label(
        [...labelAttributes(h, { htmlFor: 'switch-share', field: true })],
        [
          h.div(
            [...fieldAttributes(h)],
            [
              h.div(
                [...fieldContentAttributes(h)],
                [
                  h.div([...fieldTitleAttributes(h)], ['Share across devices']),
                  h.p(
                    [...fieldDescriptionAttributes(h)],
                    [
                      'Focus is shared across devices, and turns off when you leave the app.',
                    ],
                  ),
                ],
              ),
              ...switchControl(h, { id: 'switch-share' }),
            ],
          ),
        ],
      ),
      h.label(
        [
          ...labelAttributes(h, {
            htmlFor: 'switch-notifications',
            field: true,
          }),
        ],
        [
          h.div(
            [...fieldAttributes(h)],
            [
              h.div(
                [...fieldContentAttributes(h)],
                [
                  h.div([...fieldTitleAttributes(h)], ['Enable notifications']),
                  h.p(
                    [...fieldDescriptionAttributes(h)],
                    [
                      'Receive notifications when focus mode is enabled or disabled.',
                    ],
                  ),
                ],
              ),
              ...switchControl(h, {
                id: 'switch-notifications',
                isChecked: true,
              }),
            ],
          ),
        ],
      ),
    ],
  )
}

export const SwitchDisabled = (): Html => {
  const h = html<never>()

  return h.div(
    [...fieldAttributes(h, { className: 'w-fit', isDisabled: true })],
    [
      ...switchControl(h, {
        id: 'switch-disabled-unchecked',
        isDisabled: true,
      }),
      h.label(
        [
          ...labelAttributes(h, {
            htmlFor: 'switch-disabled-unchecked',
            field: true,
          }),
        ],
        ['Disabled'],
      ),
    ],
  )
}

export const SwitchInvalid = (): Html => {
  const h = html<never>()

  return h.div(
    [...fieldAttributes(h, { className: 'max-w-sm', isInvalid: true })],
    [
      h.div(
        [...fieldContentAttributes(h)],
        [
          h.label(
            [...labelAttributes(h, { htmlFor: 'switch-terms', field: true })],
            ['Accept terms and conditions'],
          ),
          h.p(
            [...fieldDescriptionAttributes(h)],
            ['You must accept the terms and conditions to continue.'],
          ),
        ],
      ),
      ...switchControl(h, { id: 'switch-terms', isInvalid: true }),
    ],
  )
}

export const SwitchSizes = (): Html => {
  const h = html<never>()

  return h.div(
    [...fieldGroupAttributes(h, 'w-full max-w-[10rem]')],
    [
      h.div(
        [...fieldAttributes(h)],
        [
          ...switchControl(h, { id: 'switch-size-sm', size: 'sm' }),
          h.label(
            [...labelAttributes(h, { htmlFor: 'switch-size-sm', field: true })],
            ['Small'],
          ),
        ],
      ),
      h.div(
        [...fieldAttributes(h)],
        [
          ...switchControl(h, { id: 'switch-size-default', size: 'default' }),
          h.label(
            [
              ...labelAttributes(h, {
                htmlFor: 'switch-size-default',
                field: true,
              }),
            ],
            ['Default'],
          ),
        ],
      ),
    ],
  )
}

export const SwitchRtl = (): Html => {
  const h = html<never>()
  const dir = 'rtl'

  return h.div(
    [...fieldAttributes(h, { className: 'max-w-sm', dir })],
    [
      h.div(
        [...fieldContentAttributes(h)],
        [
          h.label(
            [
              ...labelAttributes(h, {
                htmlFor: 'switch-focus-mode-rtl',
                field: true,
                dir,
              }),
            ],
            ['المشاركة عبر الأجهزة'],
          ),
          h.p(
            [...fieldDescriptionAttributes(h, dir)],
            [
              'يتم مشاركة التركيز عبر الأجهزة، ويتم إيقاف تشغيله عند مغادرة التطبيق.',
            ],
          ),
        ],
      ),
      ...switchControl(h, { id: 'switch-focus-mode-rtl', dir }),
    ],
  )
}

